-- Защита: ни one пользователь не должен иметь пустого имени.
UPDATE users SET first_name = 'Без' WHERE first_name IS NULL OR TRIM(first_name) = '';
UPDATE users SET last_name  = 'имени' WHERE last_name  IS NULL OR TRIM(last_name)  = '';
